from typing import List

def solve(nums: List[int], target: int) -> int:
    n = len(nums)
    # We'll use a bitmask to represent the subset of elements we keep
    # The maximum possible bitmask is 2^n, which is manageable for n <= 40
    min_removals = float('inf')

    for mask in range(1 << n):
        xor_sum = 0
        removals = 0
        for i in range(n):
            if mask & (1 << i):
                xor_sum ^= nums[i]
            else:
                removals += 1
        if xor_sum == target:
            min_removals = min(min_removals, removals)

    return min_removals if min_removals != float('inf') else -1
